import{c as a,Q as o,j as t,m as d}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"developer/architecture.md","filePath":"developer/architecture.md","lastUpdated":null}'),r={name:"developer/architecture.md"};function c(n,e,i,s,l,h){return o(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>Audience: developers and maintainers<br> Goal: describe the main runtime pieces<br> Type: explanation/reference</p><p>The project is a Python backend/CLI with a React/Vite frontend and a separate Rhythm Lab helper app.</p><h2 id="backend" tabindex="-1">Backend <a class="header-anchor" href="#backend" aria-label="Permalink to &quot;Backend&quot;">​</a></h2><p>Important modules:</p><ul><li><code>database.py</code>: SQLite access, write serialization, summaries, relocation, resets, caches, and stored analysis state.</li><li><code>scanner.py</code>: supported audio discovery and Mutagen metadata extraction.</li><li><code>audio_loader.py</code>: shared decoding path.</li><li><code>sonara_features.py</code> and <code>sonara_jobs.py</code>: SONARA extraction and jobs.</li><li><code>genres.py</code> and <code>genre_jobs.py</code>: MAEST genre analysis jobs.</li><li><code>embedding.py</code> and <code>analysis_jobs.py</code>: MERT/CLAP embeddings and analysis orchestration.</li><li><code>classifier_scoring.py</code> and <code>classifier_jobs.py</code>: promoted classifier scoring and jobs.</li><li><code>search.py</code> and <code>sonara_similarity.py</code>: embedding and SONARA search.</li><li><code>api.py</code> and <code>cli.py</code>: FastAPI and Typer entrypoints.</li></ul><h2 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h2><p>The main UI lives under <code>frontend/</code>. <code>frontend/src/api.ts</code> mirrors backend API contracts used by React components.</p><p>The production backend serves <code>frontend/dist</code> when it exists. Run the frontend build after frontend source changes.</p><h2 id="rhythm-lab" tabindex="-1">Rhythm Lab <a class="header-anchor" href="#rhythm-lab" aria-label="Permalink to &quot;Rhythm Lab&quot;">​</a></h2><p>Rhythm Lab is under <code>tools/rhythm-lab/</code>. It has its own lab UI, CLI, labels database, training artifacts, and promotion path. Runtime promoted models for the main app live separately under <code>models/classifiers/</code>.</p><h2 id="docs" tabindex="-1">Docs <a class="header-anchor" href="#docs" aria-label="Permalink to &quot;Docs&quot;">​</a></h2><p>The VitePress docs live under <code>docs/dj-track-similarity</code> and build to <code>site</code>. The main backend mounts that generated directory at <code>/docs</code>.</p>',13)])])}const m=a(r,[["render",c]]);export{u as __pageData,m as default};
